import { DecimalPipe } from "@angular/common";
import { Component, Input, OnInit, ViewChild } from "@angular/core";
import {
  ApexNonAxisChartSeries,
  ApexPlotOptions,
  ApexChart,
  ChartComponent,
  ApexResponsive,
  ApexLegend,
  ApexDataLabels,
  ApexYAxis,
  ApexXAxis,
  ApexFill,
  ApexTooltip,
  ApexStroke,
  ApexAxisChartSeries,
} from "ng-apexcharts";

type ChartOptions = {
  series: ApexNonAxisChartSeries;
  chart: ApexChart;
  labels: string[];
  plotOptions: ApexPlotOptions;
  colors: string[];
  legend: ApexLegend;
};
export interface DashboardPieChartInput {
  first: {
    name: string;
    value: number;
  };
  second: {
    name: string;
    value: number;
  };
  finalName: string;
}
@Component({
  selector: "app-pie-chart-dashboard",
  templateUrl: "./pie-chart-dashboard.component.html",
  styleUrls: ["./pie-chart-dashboard.component.scss"],
  providers: [DecimalPipe],
})
export class PieChartDashboardComponent implements OnInit {
  @ViewChild("chart") chart: ChartComponent;
  @Input() chartInput: DashboardPieChartInput;
  public chartOptions: Partial<ChartOptions>;

  constructor(private decimalPipe: DecimalPipe) {}
  ngOnInit(): void {
    this.initializeChartUi();
    this.initialState();
  }
  initializeChartUi() {
    this.chartOptions = {
      chart: {
        height: 300,
        type: "radialBar",
      },
      plotOptions: {
        radialBar: {
          hollow: {
            size: "60%",
          },
          dataLabels: {
            name: {
              show: this.chartInput?.finalName === null ? false : true,
            },
            value: {
              show: true,
            },
          },
        },
      },
    };
  }
  initialState() {
    const { first, second, finalName } = this.chartData;
    const [firstName, firstValue, secondName, secondValue] = [
      first.name,
      first.value,
      second.name,
      second.value,
    ];

    const percentageValue = Math.floor((firstValue / secondValue) * 100) | 0;
    const formattedFirstValue = this.decimalPipe.transform(firstValue, "1.0-0");
    const formattedSecondValue = this.decimalPipe.transform(
      secondValue,
      "1.0-0"
    );

    this.chartOptions = {
      ...this.chartOptions, // Regain existing options
      series: [percentageValue],
      labels: [this.chartInput?.finalName === null ? "" : finalName],
      legend: {
        show: true,
        floating: false,
        fontSize: "16px",
        markers: {
          width: 0,
          height: 0,
        },
        position: "bottom",
        horizontalAlign: "center",
        labels: {
          useSeriesColors: false,
        },
        onItemClick: { toggleDataSeries: false },
        onItemHover: { highlightDataSeries: false },
        formatter: () =>
          `<ion-label>${firstName}: ${formattedFirstValue}</ion-label> <br> <ion-label>${secondName}: ${formattedSecondValue}</ion-label>`,
        itemMargin: { vertical: 0 },
      },
    };
  }

  get chartData() {
    return this.chartInput;
  }
}
