  async clickOnSpecificBranch(branch: DashboardBranchesOutput) {
    this.showLoader = true;

    this.selectedBranch = {
      name: branch.branchName,
      code: branch.branchCode,
    };
    await this.fetchData(this.username);

    this.dashboardLevel = 2;
    this.getUserGridFields();
  }
  async clickOnSpecificUser(username: string) {
    try {
      if (username === "اخري") {
        return;
      }
      this.showLoader = true;

      await this.fetchData(username);

      this.addingNewUserSupervisor(username);
      this.getUserGridFields();
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
