import { ChangeDetectorRef, Component, OnInit } from "@angular/core";
import { HttpErrorResponse } from "@angular/common/http";
import { BehaviorSubject } from "rxjs";

import { SlideInOutAnimation } from "../../animation/Animations";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { AlertService } from "src/app/core/services/alert.service";
import { DashboardService } from "src/app/core/services/dashboard.service";
import { UserService } from "src/app/core/services/user.service";
import { ReferencesService } from "src/app/core/services/references.service";

import { UserInfo } from "src/app/core/models/UserInfo";
import { DashboardPieChartInput } from "./pie-chart-dashboard/pie-chart-dashboard.component";
import { GetMainData } from "../../Models/Dashboard/GetMainData";
import { UserPreference } from "../../Models/Users/UserPreference";
import { StaticRef } from "../../Models/References/StaticRef";
import {
  ApexChart,
  ApexLegend,
  ApexNonAxisChartSeries,
  ApexPlotOptions,
  ApexResponsive,
} from "ng-apexcharts";

type ChartObject = {
  series: ApexNonAxisChartSeries;
  chart: ApexChart;
  labels: string[];
  colors: string[];
  legend: ApexLegend;
  plotOptions: ApexPlotOptions;
  responsive: ApexResponsive[];
};
interface ChartsDashboard {
  targetNumber: DashboardPieChartInput;
  targetAmount: DashboardPieChartInput;
}
interface DashboardSectionVisibility {
  productivity: {
    comparison: null | 1 | 2;
    targetNumber: null | 1;
    targetAmount: null | 1;
  };
  portfolio: {
    comparison: null | 1;
  };
  currentMonthOverdue: {
    notPaid: null | 1 | 2 | 3 | 4 | 5 | 6;
    paid: null | 1 | 2 | 3 | 4 | 5 | 6;
  };
  previousMonthOverdue: {
    notPaid: null | 1 | 2 | 3 | 4 | 5 | 6;
    paid: null | 1 | 2 | 3 | 4 | 5 | 6;
  };
  currentMonthAtRiskBalances: {
    notPaid: null | 1 | 2 | 3 | 4 | 5;
  };
  previousMonthAtRiskBalances: {
    notPaid: null | 1 | 2 | 3 | 4 | 5;
  };
  payment: {
    tillToday: null | 1;
    untilThisMonth: null | 1;
  };
}
@Component({
  selector: "app-dashboard",
  templateUrl: "./dashboard.page.html",
  styleUrls: ["./dashboard.page.scss"],
  animations: [SlideInOutAnimation],
})
export class DashboardPage implements OnInit {
  public productivityChart: Partial<ChartObject>;
  public showLoader: boolean = false;
  public userInfo: UserInfo;
  public mainDashboardData: GetMainData;
  public chartsDashboard: ChartsDashboard;
  public dashboardSectionVisibility: DashboardSectionVisibility;
  public userPreference: UserPreference;
  public dashboardTypeViewModel: StaticRef[] = [];
  private dashboardView = new BehaviorSubject<string | null>(null);
  public dashboardView$ = this.dashboardView.asObservable();
  public useWorkflow: number = 0;

  constructor(
    private cdref: ChangeDetectorRef,
    private authService: MohassilAuthService,
    private alertService: AlertService,
    private dashboardService: DashboardService,
    private userService: UserService,
    private referencesService: ReferencesService
  ) {}

  async ngOnInit() {
    this.showLoader = true;
    try {
      this.useWorkflow = Number(
        (await this.referencesService.getStaticValueById(26)).value
      );
      this.initializeState();
      await this.loadInitialData();
      this.applyChartsData();
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  ngAfterContentChecked() {
    this.cdref.detectChanges();
  }
  private initializeState() {
    this.mainDashboardData = null;
    this.resetDrillDownGrids();
  }
  private async loadInitialData(): Promise<void> {
    this.userInfo = await this.authService.getUserInfo();
    if (this.useWorkflow)
      this.dashboardTypeViewModel =
        await this.referencesService.getDashboardTypeView();
    this.userPreference = await this.userService
      .getUserPreference()
      .toPromise();

    if (this.useWorkflow === 1) {
      this.dashboardView.next(this.userPreference.dsh_type_view.toString());
    } else {
      this.dashboardView.next("2");
    }

    this.mainDashboardData = await this.dashboardService
      .getMainData()
      .toPromise();
  }
  private applyChartsData() {
    const { achieveNumber, targetNumber, achieveAmount, targetAmount } =
      this.dashboardData;

    this.chartsDashboard = {
      targetNumber: {
        first: {
          name: "المحقق",
          value: achieveNumber,
        },
        second: {
          name: "المستهدف",
          value: targetNumber,
        },
        finalName: null,
      },
      targetAmount: {
        first: {
          name: "المحقق",
          value: achieveAmount,
        },
        second: {
          name: "المستهدف",
          value: targetAmount,
        },
        finalName: null,
      },
    };
  }
  resetDrillDownGrids() {
    this.dashboardSectionVisibility = {
      productivity: {
        comparison: null,
        targetAmount: null,
        targetNumber: null,
      },
      portfolio: {
        comparison: null,
      },
      currentMonthOverdue: {
        notPaid: null,
        paid: null,
      },
      previousMonthOverdue: {
        notPaid: null,
        paid: null,
      },
      currentMonthAtRiskBalances: {
        notPaid: null,
      },
      previousMonthAtRiskBalances: {
        notPaid: null,
      },
      payment: {
        tillToday: null,
        untilThisMonth: null,
      },
    };
  }
  get dashboardData() {
    return this.mainDashboardData;
  }
  get dashboardTypeView() {
    return Number(this.dashboardView.value);
  }
  updateDashboardView(viewType: number) {
    this.dashboardView.next(viewType.toString());
    this.resetDrillDownGrids();
  }
  private handleError(error: unknown) {
    const errorMessage =
      error instanceof HttpErrorResponse
        ? JSON.stringify(error.error)
        : error instanceof Error
        ? error.message
        : String(error);

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
