import {
  trigger,
  state,
  style,
  transition,
  animate,
  group,
} from "@angular/animations";
import { translate } from "ol/transform";

export const SlideInOutAnimation = [
  trigger("slideInOut", [
    transition(":leave", [
      style({ opacity: 1 }),
      group([
        animate(
          "1500ms ease-in-out",
          style({
            visibility: "hidden",
            "max-height": "0px",
            opacity: "0",
          })
        ),
      ]),
    ]),
    transition(":enter", [
      style({ opacity: 0 }),
      group([
        animate(
          "2500ms ease-in-out",
          style({
            visibility: "visible",
            "max-height": "500px",
            opacity: "1",
          })
        ),
      ]),
    ]),
  ]),
];

export const SlideLeftRightAnimation = [
  trigger("slideLeftRight", [
    transition(":leave", [
      style({ trasform: "translateX(0%)", opacity: 1 }),
      group([
        animate(
          "500ms ease-in-out",
          style({
            transform: "translateX(100%)",
            opacity: "0",
          })
        ),
      ]),
    ]),
    transition(":enter", [
      style({ transform: "translateX(-100%)", opacity: 0 }),
      group([
        animate(
          "500ms ease-in-out",
          style({
            transform: "translateX(0%)",
            opacity: "1",
          })
        ),
      ]),
    ]),
  ]),
];
