import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { Observable } from "rxjs";

import { AlertService } from "./alert.service";
import { EnvService } from "./env.service";
import {
  GetUserSupervisionDashBoardRequest,
  GetUserSupervisionDashBoardResponse,
} from "src/app/views/Models/Dashboard/GetUserSupervisionDashBoard";
import {
  GetUserHierarchyDetailsRequest,
  GetUserHierarchyDetailsResponse,
} from "src/app/views/Models/Dashboard/GetUserHierarchyDetails";
import {
  GetUserSupervisionDetailsRequest,
  GetUserSupervisionDetailsResponse,
} from "src/app/views/Models/Dashboard/GetUserSupervisionDetails";
import {
  GetUserHierarchyRequest,
  GetUserHierarchyResponse,
} from "src/app/views/Models/Dashboard/GetUserHierarchy";
import { GetMainData } from "src/app/views/Models/Dashboard/GetMainData";
import {
  GetUserBranchesSummaryRequest,
  GetUserBranchesSummaryResponse,
} from "src/app/views/Models/Dashboard/GetUserBranchesSummary";

@Injectable({
  providedIn: "root",
})
export class DashboardService {
  constructor(
    private env: EnvService,
    private http: HttpClient,
    private alertService: AlertService
  ) {}

  getUserSupervisionDashBoard = (
    request: GetUserSupervisionDashBoardRequest
  ) => {
    try {
      const result = this.http
        .post<GetUserSupervisionDashBoardResponse>(
          this.env.API_URL + `api/DashBoard/GetUserSupervisionDashBoard`,
          {
            username: request.username,
          }
        )
        .toPromise();
      return result;
    } catch (error) {
      console.error("Error GetUserSupervisionDashBoard:", error);
      throw error;
    }
  };

  getUserHierarchyDashBoard = (request: GetUserHierarchyRequest) => {
    try {
      const result = this.http
        .post<GetUserHierarchyResponse>(
          this.env.API_URL + `api/DashBoard/GetUserHierarchyDashBoard`,
          {
            username: request.username,
          }
        )
        .toPromise();
      return result;
    } catch (error) {
      console.error("Error GetUserHierarchyDashBoard:", error);
      throw error;
    }
  };

  getUserSupervisionDetails = (request: GetUserSupervisionDetailsRequest) => {
    try {
      return this.http.post<GetUserSupervisionDetailsResponse>(
        this.env.API_URL + `api/DashBoard/GetUserSupervisionDetails`,
        {
          username: request.username,
          dashboardSection: request.dashboardSection,
          branchCode: request.branchCode,
        }
      );
    } catch (error) {
      console.error("Error GetUserSupervisionDetails:", error);
      throw error;
    }
  };

  getUserHierarchyDetails = (request: GetUserHierarchyDetailsRequest) => {
    try {
      return this.http.post<GetUserHierarchyDetailsResponse>(
        this.env.API_URL + `api/DashBoard/GetUserHierarchyDetails`,
        {
          username: request.username,
          dashboardSection: request.dashboardSection,
          branchCode: request.branchCode,
        }
      );
    } catch (error) {
      console.error("Error GetUserHierarchyDetails:", error);
      throw error;
    }
  };
  getMainData = () => {
    try {
      return this.http.get<GetMainData>(
        this.env.API_URL + `api/DashBoard/GetMainData`
      );
    } catch (error) {
      console.error("Error getMainData:", error);
      throw error;
    }
  };
  getUserBranchesSummary = (request: GetUserBranchesSummaryRequest) => {
    try {
      return this.http.post<GetUserBranchesSummaryResponse[]>(
        this.env.API_URL + `api/DashBoard/GetUserBranchesSummary`,
        {
          username: request.username,
        }
      );
    } catch (error) {
      console.error("Error getUserBranchesSummary:", error);
      throw error;
    }
  };
}
