import { HttpErrorResponse } from "@angular/common/http";
import { Component, EventEmitter, Input, OnInit, Output } from "@angular/core";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { DashboardService } from "src/app/core/services/dashboard.service";
import { UserService } from "src/app/core/services/user.service";
import { GetUserSupervisionDetailsResponse } from "src/app/views/Models/Dashboard/GetUserSupervisionDetails";
import { DashboardBranchesOutput } from "../dashboard-branches-grid/dashboard-branches-grid.component";
enum DashboardLevels {
  hide = 0,
  branch = 1,
  users = 2,
}
@Component({
  selector: "app-drill-down-supervision",
  templateUrl: "./drill-down-supervision.component.html",
  styleUrls: ["./drill-down-supervision.component.css"],
})
export class DrillDownSupervisionComponent implements OnInit {
  //#region Variables
  showLoader: boolean = false;
  dashboardLevel: DashboardLevels = 1;
  dashboardBranchesOutput: DashboardBranchesOutput;
  //#endregion

  @Input() section: number;
  @Input() subSection: number;
  @Output() closeComponent: EventEmitter<boolean> = new EventEmitter(false);

  constructor(private alertService: AlertService) {}

  async ngOnInit() {
    try {
      this.showLoader = true;
      this.dashboardBranchesOutput = { branchCode: null, branchName: null };
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  backButton() {
    if (this.dashboardLevel === 2) {
      this.dashboardLevel = 1;
      return;
    }

    this.closeComponent.emit(true);
  }

  clickOnSpecificBranch(branch: DashboardBranchesOutput) {
    this.dashboardBranchesOutput = branch;

    this.dashboardLevel = 2;
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
