import { Component, EventEmitter, Input, OnInit, Output } from "@angular/core";

export interface DashboardUserGrid {
  header: {
    first: string;
    second: string;
    third: string;
    fourth?: string;
    fifth?: string;
  };
  row: {
    firstCol: string;
    secondCol: number;
    thirdCol: number;
    fourthCol?: number;
    fifthCol?: number;
  }[];
}
@Component({
  selector: "app-dashboard-users-grid",
  templateUrl: "./dashboard-users-grid.component.html",
  styleUrls: ["./dashboard-users-grid.component.css"],
})
export class DashboardUsersGridComponent implements OnInit {
  @Input() dashboardUserGrid: DashboardUserGrid;
  @Output() usernameOutput: EventEmitter<string> = new EventEmitter();

  constructor() {}

  ngOnInit() {}
  clickOnSpecificUser(username: string) {
    this.usernameOutput.emit(username);
  }
}
